import type { CoachingAdvice } from '@motivation/shared';
import { HealthService } from '../../../services/health.service.js';
import { coachingPreferencesService } from '../../../services/coaching-preferences.service.js';
import { appTodayString, getAppTimeZone } from '../../../services/app-timezone.service.js';
import { buildSectionPage } from '../../../utils/section-page.utils.js';
import {
    createScreenStatusNodes,
    createScreenStatusMixin,
} from '../../_shared/screen-status.ts';
import type { ScreenComponent } from '../../../types/screen-component.js';
import { createComponentLogger } from '../../../utils/component-logger.js';

const template = document.createElement('template');
template.innerHTML = `
    <section class="coaching" data-testid="coaching-section">
        <header class="coaching__meta">
            <p class="coaching__stamp" data-testid="coaching-generated-at" hidden></p>
            <button type="button" class="coaching__regen" data-testid="coaching-regenerate" hidden>Re-queue coaching</button>
        </header>
        <article class="coaching__body" data-testid="coaching-advice" hidden></article>
        <p class="coaching__pending" data-testid="coaching-pending" hidden>
            Coaching is queued. The next overnight run will generate a fresh note.
        </p>
        <p class="coaching__empty" data-testid="coaching-empty" hidden>
            No coaching yet. The first overnight run will populate this screen.
        </p>
        <details class="coaching__settings" data-testid="coaching-settings">
            <summary>Tune your coach</summary>
            <form class="coaching__settings-form" data-testid="coaching-settings-form">
                <label class="coaching__field">
                    <span>Goals</span>
                    <textarea name="goals" data-testid="coaching-goals-input" rows="3" placeholder="e.g. lose 5kg by August, sub-22 5k"></textarea>
                </label>
                <label class="coaching__field">
                    <span>Tone</span>
                    <textarea name="tone" data-testid="coaching-tone-input" rows="3" placeholder="e.g. blunt, no fluff"></textarea>
                </label>
                <div class="coaching__settings-actions">
                    <button type="submit" data-testid="coaching-settings-save">Save</button>
                    <span class="coaching__settings-status" data-testid="coaching-settings-status" hidden>Saved</span>
                </div>
            </form>
        </details>
    </section>
`;

function formatRelativeStamp(generatedAt: string | null, today: string): string {
    if (!generatedAt) return '';
    try {
        const generated = Temporal.Instant.from(generatedAt);
        const generatedDate = generated.toZonedDateTimeISO(getAppTimeZone()).toPlainDate().toString();
        if (generatedDate === today) return `Generated today at ${generated.toZonedDateTimeISO(getAppTimeZone()).toPlainTime().toString({ smallestUnit: 'minute' })}`;
        return `Generated on ${generatedDate}`;
    } catch {
        return `Generated at ${generatedAt}`;
    }
}

export class HealthCoachingScreen extends HTMLElement implements ScreenComponent {
    private initialized = false;
    private content: HTMLElement | null = null;
    private status: ReturnType<typeof createScreenStatusMixin> | null = null;
    private statusNodes: ReturnType<typeof createScreenStatusNodes> | null = null;
    private adviceEl: HTMLElement | null = null;
    private stampEl: HTMLElement | null = null;
    private regenBtn: HTMLButtonElement | null = null;
    private pendingEl: HTMLElement | null = null;
    private emptyEl: HTMLElement | null = null;
    private goalsInput: HTMLTextAreaElement | null = null;
    private toneInput: HTMLTextAreaElement | null = null;
    private settingsForm: HTMLFormElement | null = null;
    private settingsStatus: HTMLElement | null = null;
    private readonly log = createComponentLogger('health-coaching-screen');

    setLoading(): void {
        this.status?.setLoading();
    }
    setError(err: unknown): void {
        this.status?.setError(err);
    }
    clearStatus(): void {
        this.status?.clearStatus();
    }

    connectedCallback(): void {
        if (this.initialized) {
            void this.load();
            return;
        }
        this.initialized = true;

        const page = buildSectionPage(this, 'Coaching', 'health', '/health');
        this.content = page.content;

        const fragment = template.content.cloneNode(true) as DocumentFragment;
        page.content.appendChild(fragment);

        this.adviceEl = page.content.querySelector('[data-testid="coaching-advice"]');
        this.stampEl = page.content.querySelector('[data-testid="coaching-generated-at"]');
        this.regenBtn = page.content.querySelector<HTMLButtonElement>('[data-testid="coaching-regenerate"]');
        this.pendingEl = page.content.querySelector('[data-testid="coaching-pending"]');
        this.emptyEl = page.content.querySelector('[data-testid="coaching-empty"]');
        this.goalsInput = page.content.querySelector<HTMLTextAreaElement>('[data-testid="coaching-goals-input"]');
        this.toneInput = page.content.querySelector<HTMLTextAreaElement>('[data-testid="coaching-tone-input"]');
        this.settingsForm = page.content.querySelector<HTMLFormElement>('[data-testid="coaching-settings-form"]');
        this.settingsStatus = page.content.querySelector<HTMLElement>('[data-testid="coaching-settings-status"]');

        this.statusNodes = createScreenStatusNodes();
        page.content.appendChild(this.statusNodes.loadingNode);
        page.content.appendChild(this.statusNodes.errorNode);
        page.content.appendChild(this.statusNodes.retryNode);
        this.status = createScreenStatusMixin(
            this.statusNodes.loadingNode,
            this.statusNodes.errorNode,
            this.statusNodes.retryNode,
        );

        this.statusNodes.retryNode.addEventListener('click', () => {
            void this.requeue();
        });
        this.regenBtn?.addEventListener('click', () => {
            void this.requeue();
        });
        this.settingsForm?.addEventListener('submit', (event) => {
            event.preventDefault();
            void this.savePreferences();
        });

        void this.loadPreferences();
        void this.load();
    }

    private async loadPreferences(): Promise<void> {
        try {
            const prefs = await coachingPreferencesService.get();
            if (this.goalsInput) this.goalsInput.value = prefs.goals;
            if (this.toneInput) this.toneInput.value = prefs.tone;
        } catch (err) {
            this.log.error('coachingPreferencesService.get failed:', err);
        }
    }

    private async savePreferences(): Promise<void> {
        if (!this.goalsInput || !this.toneInput) return;
        try {
            await coachingPreferencesService.set({
                goals: this.goalsInput.value,
                tone: this.toneInput.value,
            });
            if (this.settingsStatus) {
                this.settingsStatus.hidden = false;
                this.settingsStatus.textContent = 'Saved';
            }
        } catch (err) {
            this.log.error('coachingPreferencesService.set failed:', err);
            if (this.settingsStatus) {
                this.settingsStatus.hidden = false;
                this.settingsStatus.textContent = err instanceof Error ? `Save failed: ${err.message}` : 'Save failed';
            }
        }
    }

    private hideAll(): void {
        if (this.adviceEl) this.adviceEl.hidden = true;
        if (this.stampEl) this.stampEl.hidden = true;
        if (this.regenBtn) this.regenBtn.hidden = true;
        if (this.pendingEl) this.pendingEl.hidden = true;
        if (this.emptyEl) this.emptyEl.hidden = true;
    }

    private renderRow(row: CoachingAdvice | null): void {
        this.hideAll();
        this.clearStatus();

        if (!row) {
            if (this.emptyEl) this.emptyEl.hidden = false;
            return;
        }

        if (row.status === 'failed') {
            this.setError(row.error ?? 'Coaching generation failed without an error message.');
            return;
        }

        if (row.status === 'pending') {
            if (this.pendingEl) this.pendingEl.hidden = false;
            if (this.regenBtn) this.regenBtn.hidden = false;
            return;
        }

        // status === 'done'
        if (this.adviceEl) {
            this.adviceEl.textContent = row.advice ?? '';
            this.adviceEl.hidden = false;
        }
        if (this.stampEl && row.generated_at) {
            const today = appTodayString();
            this.stampEl.textContent = formatRelativeStamp(row.generated_at, today);
            this.stampEl.hidden = false;
        }
        if (this.regenBtn) this.regenBtn.hidden = false;
    }

    private async load(): Promise<void> {
        this.setLoading();
        try {
            const row = await HealthService.fetchCoaching();
            this.renderRow(row);
        } catch (err) {
            this.log.error('fetchCoaching failed:', err);
            this.setError(err);
        }
    }

    private async requeue(): Promise<void> {
        try {
            await HealthService.requestCoachingGeneration();
            await this.load();
        } catch (err) {
            this.log.error('requestCoachingGeneration failed:', err);
            this.setError(err);
        }
    }
}

if (!customElements.get('health-coaching-screen')) {
    customElements.define('health-coaching-screen', HealthCoachingScreen);
}
