import type { DbDriver } from '@motivation/shared';
import { DbService } from '../db/db.service.js';

/**
 * Story 074 — user-editable prompt context for the overnight coaching run.
 * Stored as two separate `settings` rows (`coaching.goals`, `coaching.tone`)
 * so each can be cleared independently. The server reads them at prompt-
 * construction time via `settingsRepository.get(...)`; the local writes
 * propagate via the standard settings sync.
 */
export const COACHING_GOALS_KEY = 'coaching.goals';
export const COACHING_TONE_KEY = 'coaching.tone';

export interface CoachingPreferences {
    goals: string;
    tone: string;
}

export interface CoachingPreferencesServiceDeps {
    driver?: () => Promise<DbDriver>;
}

async function defaultDriver(): Promise<DbDriver> {
    const service = DbService.getInstance();
    await service.init();
    return service.driver;
}

export class CoachingPreferencesService {
    private readonly driverFn: () => Promise<DbDriver>;

    constructor(deps: CoachingPreferencesServiceDeps = {}) {
        this.driverFn = deps.driver ?? defaultDriver;
    }

    async get(): Promise<CoachingPreferences> {
        const driver = await this.driverFn();
        const [goalsRows, toneRows] = await Promise.all([
            driver.query<{ value: string }>('SELECT value FROM settings WHERE key = ?', COACHING_GOALS_KEY),
            driver.query<{ value: string }>('SELECT value FROM settings WHERE key = ?', COACHING_TONE_KEY),
        ]);
        return {
            goals: goalsRows[0]?.value ?? '',
            tone: toneRows[0]?.value ?? '',
        };
    }

    async set(partial: Partial<CoachingPreferences>): Promise<void> {
        const driver = await this.driverFn();
        if (partial.goals !== undefined) {
            await driver.execute(
                `INSERT INTO settings (key, value) VALUES (?, ?)
                 ON CONFLICT(key) DO UPDATE SET value = excluded.value, updated_at = datetime('now')`,
                COACHING_GOALS_KEY,
                partial.goals,
            );
        }
        if (partial.tone !== undefined) {
            await driver.execute(
                `INSERT INTO settings (key, value) VALUES (?, ?)
                 ON CONFLICT(key) DO UPDATE SET value = excluded.value, updated_at = datetime('now')`,
                COACHING_TONE_KEY,
                partial.tone,
            );
        }
    }
}

export const coachingPreferencesService = new CoachingPreferencesService();
